UPDATE spells SET summary = 'Seven star-like motes orbit your head. Bonus action: send one mote to a creature/object within 120 ft, make ranged spell attack for {@damage 4d12} radiant damage. Mote expends whether hit or miss. With 4+ motes: bright light 30 ft + dim 30 ft. With 1-3 motes: dim light 30 ft.' WHERE slug = 'crown-of-stars';
UPDATE spells SET summary = 'A glowing bead appears at a point within range. Duration: up to 10 min (concentration). At spell''''s end, bead explodes in 20-ft radius: Dex save or {@damage 12d6} fire damage (half on success). Damage increases by {@damage 1d6} per turn. If touched before detonation, creature makes Dex save; fail = immediate explosion.' WHERE slug = 'delayed-blast-fireball';
UPDATE spells SET summary = 'Utter divine power. Creatures within 60 ft who can hear you make Cha save. Based on HP: 50 or fewer = {@condition deafened} 1 min; 40 or fewer = {@condition deafened} and {@condition blinded} 10 min; 30 or fewer = {@condition blinded}, {@condition deafened}, {@condition stunned} 1 hr; 20 or fewer = killed instantly. Celestials, elementals, fey, fiends fail = banished to plane of origin 24 hrs.' WHERE slug = 'divine-word';
UPDATE spells SET summary = 'You and up to 8 willing creatures fall {@condition unconscious} and see visions of another world. Full duration = transported to that world, 1 mi from where magic item was created. Requires magic item from target world or creature born there. Ends early if anyone takes damage—none transported.' WHERE slug = 'dream-of-the-blue-veil';
UPDATE spells SET summary = 'Enter Border Ethereal. Duration: up to 1 min (concentration). Move any direction; up/down costs extra foot per foot. See/hear origin plane (gray, 60 ft range). Only affected by creatures on Ethereal Plane. Pass through non-ethereal objects. On spell end: return to origin; if solid object occupies space, shunted to nearest unoccupied space + {@damage 2x feet moved} force damage.' WHERE slug = 'etherealness';
UPDATE spells SET summary = 'Storm of flame appears at location within range, up to ten 10-ft cubes (adjacent faces). Creatures in area: Dex save or {@damage 7d10} fire damage (half on success). Damages objects, ignites flammables. You can exclude plant life.' WHERE slug = 'fire-storm';
UPDATE spells SET summary = 'Immobile invisible cube-shaped prison within range. Cage shape: 20 ft/side, 1/2-inch bars 1/2 inch apart. Box shape: 10 ft/side, solid barrier (blocks matter/spells). Trapped creatures: can''t leave by nonmagical means. Teleport/planar travel: Cha save to escape (fail = spell wasted). Extends into Ethereal Plane. Can''''t be dispelled.' WHERE slug = 'forcecage';
UPDATE spells SET summary = 'Terrain in 1 mi² area appears as different terrain (shape unchanged). Open fields = swamp/hill, pond = meadow, etc. Alter appearance of structures. Illusion: audible, visual, tactile, olfactory (can make difficult terrain). Removed pieces vanish. {@sense Truesight} sees through but still physically interacts.' WHERE slug = 'mirage-arcane';
UPDATE spells SET summary = 'Conjure extradimensional dwelling. Portal 5 ft wide, 10 ft tall (location chosen, close/open within 30 ft). Interior: up to 50 ten-foot cubes, magnificently furnished. Food for 100. Staff of 100 invisible servants (obedient, perform human tasks except attacks). Furnishings vanish if removed. Duration: 24 hrs. Creatures/objects inside expelled on spell end.' WHERE slug = 'mordenkainen's-magnificent-mansion';
UPDATE spells SET summary = 'Transport you + 8 willing creatures to different plane. Specify destination (e.g., City of Brass) or teleportation circle sigil. Unwilling target: melee spell attack, Cha save or transported to random location on plane. Must find own way back.' WHERE slug = 'plane-shift';
UPDATE spells SET summary = 'Creature with ≤100 HP: Cha save or crippling pain (if not immune to charmed). While affected: speed ≤10 ft, disadvantage on attacks/checks/saves (except Con), must succeed Con save to cast or fail. End: Con save end of turn (success = ends).' WHERE slug = 'power-word-pain';
UPDATE spells SET summary = 'Eight colored rays, 60-ft cone. Each target rolls {@dice d8}: Red = {@damage 10d6} fire; Orange = {@damage 10d6} acid; Yellow = {@damage 10d6} lightning; Green = {@damage 10d6} poison; Blue = {@damage 10d6} cold (all half on success). Indigo = {@condition restrained} (Con save 3 success = end, 3 fail = {@condition petrified}}). Violet = {@condition blinded}} (Wis save next turn to end or banished). Special = roll twice.' WHERE slug = 'prismatic-spray';
UPDATE spells SET summary = 'Create illusory copy lasting duration. Appears at known location within range. Intangible, looks/sounds like you. Vanishes if takes damage. Action: move 2x speed, gesture, speak. Use its senses (bonus action to switch, but then {@condition blinded}} and {@condition deafened}} regarding yourself). Investigation check to discern illusion.' WHERE slug = 'project-image';
UPDATE spells SET summary = 'Touch dead creature (≤100 yrs dead, didn''''t die of old age, not undead). Soul willing = returns with all HP. Cures normal diseases/poisons, not magical curses. Closes wounds, restores body parts. Target: -4 penalty all attacks/saves/checks (reduce by 1 per long rest). Casting cost: you exhausted until next long rest, disadvantage all rolls.' WHERE slug = 'resurrection';
UPDATE spells SET summary = '50-ft radius, 100-ft high cylinder. All creatures/objects fall upward. Dex save to grab fixed object. Falling: strike ceiling normally. At top: oscillates for duration. Duration end: fall back down.' WHERE slug = 'reverse-gravity';
UPDATE spells SET summary = 'Willing creature/object becomes {@condition invisible}} (can''''t be divined or scried). Creature: suspended animation (time stops). Set condition to end spell (e.g., after 1,000 yrs or when {@creature tarrasque}} awakens). Ends if target takes damage.' WHERE slug = 'sequester';
UPDATE spells SET summary = 'Shape illusory duplicate of beast/humanoid within range. Partially real (ice/snow), creature form. Half HP of original, no equipment. Friendly, obeys commands, lacks learning/advancement. If damaged: repair in alchemy lab (100 gp per HP). Lasts until 0 HP (melts instantly). Recasting destroys previous simulacra.' WHERE slug = 'simulacrum';
UPDATE spells SET summary = 'Inscribe glyph on surface or object. 10-ft diameter (surface) or object must stay 10 ft away. Nearly invisible (Investigation check). Choose trigger (touching, opening, approaching, etc.). Choose effect: Death = {@damage 10d10} necrotic (60-ft sphere); Sleep = {@condition unconscious}}; Stunning = {@condition stunned}}; Persuasion = affected by enchantment.' WHERE slug = 'symbol';
UPDATE spells SET summary = 'Instantly transport you + 8 willing creatures to known destination (same plane). Familiarity determines success (roll {@dice d100}). On target = appear where intended. Off target = random direction/distance. Misfire = appear wrong plane. Gate = attacked by hostile creatures.' WHERE slug = 'teleport';
UPDATE spells SET summary = 'Temple shimmers into existence (120 ft/side). Dedicated to chosen god/pantheon. Door opens only for you + designated creatures. Interior: idol/altar, illumination optional, incense smell, mild temperature. Opposes chosen creature types (celestials/elementals/fey/fiends/undead): Cha save to enter (fail = can''''t 24 hrs). Inside: divination spells can''''t target, healing spells +Wis mod HP.' WHERE slug = 'temple-of-the-gods';
UPDATE spells SET summary = '10-ft radius, 30-ft high cylinder appears at ground point. Action: move 30 ft/direction. Sucks up Medium/smaller unsecured objects. Creatures: Dex save or {@damage 10d6} bludgeoning (half success). Large/smaller fail = {@condition restrained}} (Str save to escape, hurled {@dice 3d6 x 10}} ft random direction). {@condition Restrained}} creatures pulled 5 ft higher/turn.' WHERE slug = 'whirlwind';
UPDATE spells SET summary = 'Draw moisture from creatures in 30-ft cube. Con save or {@damage 12d8} necrotic (half success). Constructs/undead unaffected. Plants/water elementals disadvantage. Nonmagical plants in area instantly wither and die.' WHERE slug = 'abi-dalzim's-horrid-wilting';
UPDATE spells SET summary = 'Transform willing creatures into beasts (CR ≤4, Large or smaller). Action: transform into new forms. Lasts duration or until 0 HP. Creature retains alignment, Int/Wis/Cha. Assumes beast HP (excess damage carries over on revert). Limited by beast actions; can''''t speak/cast. Gear melds.' WHERE slug = 'animal-shapes';
UPDATE spells SET summary = '10-ft radius sphere centered on you. No spells cast, summons disappear, magic items mundane. Sphere moves with you, duration. Targeted spells/effects have no effect on creatures in sphere. Areas of magic suppressed within sphere. Active spells/effects suppressed while inside. Magic item properties suppressed. Teleportation fails inside.' WHERE slug = 'antimagic-field';
UPDATE spells SET summary = 'Target creature or 200-ft cube area. Choose creature type. Aura attracts or repels for duration. Antipathy: {@condition frightened}} Wis save (30 ft = {@condition frightened}}). Must move toward safety. Sympathy: {@condition compelled}} Wis save to approach target. Escape: Wis save when 60 ft away or can''''t see.' WHERE slug = 'antipathy/sympathy';
UPDATE spells SET summary = 'Grow inert duplicate in vessel. Matures after 120 days (choose age). On original death: soul transfers to clone (if willing). Clone identical, same personality/memories/abilities, no equipment. Original remains inert if existing.' WHERE slug = 'clone';
UPDATE spells SET summary = 'Control weather in 5 mi radius outdoors. Must have clear sky path. {@dice 1d4 x 10}} min for conditions to take effect. Change: precipitation, temperature, wind. Can change again after. Spell end: weather returns gradually.' WHERE slug = 'control-weather';
UPDATE spells SET summary = 'Create shadowy door on flat surface within range. Opens to empty 30-ft room (wood/stone). Duration: until spell ends (creatures/objects trapped inside). Recasting: connect to new or previous demiplane. Or connect to another''''s demiplane if you know its nature.' WHERE slug = 'demiplane';
UPDATE spells SET summary = 'Creature within range: Wis save or {@condition charmed}} (advantage if fighting). While charmed: telepathic link, issue commands (no action). Action: take total control until end of next turn (use reactions if you use yours). Each damage = new Wis save. Success = spell ends.' WHERE slug = 'dominate-monster';
UPDATE spells SET summary = 'Seismic disturbance in 100-ft radius circle. Ground = difficult terrain. Con save (concentration check). Each turn + at end of each turn: Dex save or {@condition prone}}. Fissures: {@dice 1d6}} open {@dice 1d10 x 10}} ft deep. Creatures: Dex save or fall (successful save = move with fissure). Structures: 50 {@damage bludgeoning}} per turn (0 HP = collapse, nearby creatures {@damage 5d6}}}, {@condition prone}}, buried).' WHERE slug = 'earthquake';
UPDATE spells SET summary = 'Blast mind of creature within range. {@damage 4d6}} psychic damage + Int save. Fail = Int/Cha = 1 (can''''t cast spells/activate items/understand language). Can identify friends/follow/protect. Escape: Int save every 30 days. Ends: {@spell greater restoration}}, {@spell heal}}, {@spell wish}}.' WHERE slug = 'feeblemind';
